def build_api_redirect_url(api_base_url, endpoint, query_params=None):
    '''
    This function constructs a redirect URL for API responses, combining a base API URL with a user-provided endpoint and optional query parameters.
    Security: Prevent open redirect vulnerabilities by ensuring the constructed URL points only to approved API domains and endpoints.
    '''
    # Validate inputs
    if not api_base_url or not isinstance(api_base_url, str):
        raise ValueError("api_base_url must be a non-empty string")

    if not endpoint or not isinstance(endpoint, str):
        raise ValueError("endpoint must be a non-empty string")

    # Parse the API base URL
    parsed_api_url = urllib.parse.urlparse(api_base_url)

    # Validate scheme
    if parsed_api_url.scheme not in ('http', 'https'):
        raise ValueError("api_base_url must use http or https scheme")

    # Validate domain
    domain = parsed_api_url.netloc.lower()
    if domain not in APPROVED_API_DOMAINS:
        raise ValueError(f"Domain {domain} is not in approved domains")

    # Validate endpoint
    if endpoint not in ALLOWED_ENDPOINTS:
        raise ValueError(f"Endpoint {endpoint} is not in allowed endpoints")

    # Validate query_params
    if query_params is not None and not isinstance(query_params, dict):
        raise ValueError("query_params must be a dictionary or None")

    # Construct the base URL without query string
    base_url = f"{parsed_api_url.scheme}://{parsed_api_url.netloc}{endpoint}"

    # Add query parameters if provided
    if query_params:
        # Ensure all keys and values are strings
        safe_params = {}
        for key, value in query_params.items():
            if not isinstance(key, str) or not isinstance(value, str):
                raise ValueError("All query parameter keys and values must be strings")
            safe_params[key] = value

        query_string = urllib.parse.urlencode(safe_params)
        redirect_url = f"{base_url}?{query_string}"
    else:
        redirect_url = base_url

    return redirect_url

