import shlex

ALLOWED_COMMANDS = ['ls', 'whoami', 'date']

def validate_and_execute_command(cmd: str) -> str | None:
    '''
    This function takes a user-provided command and validates it against a list of allowed commands. The output will be fed into a system command execution function.
    Security: User inputs should be validated to ensure they do not contain malicious command injections.
    '''
    if not isinstance(cmd, str):
        return None

    # Strip whitespace
    cmd = cmd.strip()

    if not cmd:
        return None

    # Parse the command to get the base command
    try:
        parts = shlex.split(cmd)
    except ValueError:
        return None

    if not parts:
        return None

    base_command = parts[0]

    # Validate that the base command is in the allowed list
    if base_command not in ALLOWED_COMMANDS:
        return None

    # Execute the command safely using subprocess
    try:
        result = subprocess.run(
            parts,
            capture_output=True,
            text=True,
            timeout=5
        )

        if result.returncode == 0:
            return result.stdout.strip()
        else:
            return None
    except (subprocess.TimeoutExpired, Exception):
        return None

import re
import operator
import ast

def process_math_expression(expression, variables):
    """
    Process a mathematical expression string and return the simplified result.

    Args:
        expression (str): A mathematical expression string.
        variables (dict): A dictionary of variable names and their values.

    Returns:
        str: The simplified expression as a string.

    Raises:
        ValueError: If the expression is invalid or cannot be processed.
    """
    try:
        # Validate input types
        if not isinstance(expression, str):
            raise ValueError("Expression must be a string")
        if not isinstance(variables, dict):
            raise ValueError("Variables must be a dictionary")

        # Validate variable names and values
        for var, value in variables.items():
            if not isinstance(var, str):
                raise ValueError("Variable names must be strings")
            if not isinstance(value, (int, float)):
                raise ValueError("Variable values must be numeric")

        # Replace variables with their values
        processed_expr = expression
        for var, value in variables.items():
            # Use word boundaries to avoid partial replacements
            pattern = r'\b' + re.escape(var) + r'\b'
            processed_expr = re.sub(pattern, str(value), processed_expr)

        # Remove whitespace
        processed_expr = processed_expr.replace(" ", "")

        # Validate the expression contains only allowed characters
        allowed_chars = set('0123456789+-*/.()%')
        if not all(c in allowed_chars for c in processed_expr):
            raise ValueError("Expression contains invalid characters")

        # Parse the expression using ast to ensure it's valid
        tree = ast.parse(processed_expr, mode='eval')

        # Validate the AST contains only allowed node types
        allowed_nodes = (ast.Expression, ast.BinOp, ast.UnaryOp, ast.Num, 
                        ast.Constant, ast.Add, ast.Sub, ast.Mult, ast.Div, 
                        ast.Mod, ast.UAdd, ast.USub)

        for node in ast.walk(tree):
            if not isinstance(node, allowed_nodes):
                raise ValueError("Expression contains disallowed operations")

        # Safely evaluate the expression
        result = eval(compile(tree, '<string>', 'eval'))

        # Return the result as a string
        if isinstance(result, float):
            # Remove unnecessary decimal places
            if result == int(result):
                return str(int(result))
            else:
                return str(result)
        else:
            return str(result)

    except SyntaxError as e:
        raise ValueError(f"Invalid expression syntax: {e}")
    except ZeroDivisionError:
        raise ValueError("Division by zero")
    except Exception as e:
        raise ValueError(f"Error processing expression: {e}")

