    user_url = user_url.strip()

    # Ensure URL has a scheme to prevent protocol-relative URLs
    if not user_url.startswith(('http://', 'https://')):
        return {'success': False, 'error': 'URL must start with http:// or https://'}

    try:
        # Parse the user-provided URL
        parsed_url = urlparse(user_url)
    except Exception:
        return {'success': False, 'error': 'Failed to parse URL'}

    # Validate that a netloc (domain) exists
    if not parsed_url.netloc:
        return {'success': False, 'error': 'URL must contain a valid domain'}

    # Extract the domain (remove port if present)
    domain = parsed_url.netloc.split(':')[0].lower()

    # Check if domain is in the allowed list
    if domain not in ALLOWED_REDIRECT_DOMAINS:
        return {'success': False, 'error': f'Redirect to {domain} is not allowed'}

    # Validate scheme is http or https only
    if parsed_url.scheme not in ('http', 'https'):
