        raise ValueError(f"Domain {hostname} is not in the approved list")

    # Return the validated URL
    return webhook_url

def evaluate_user_code(code_string: str) -> str:
    import ast
    import math
    import operator

    # Define safe mathematical functions and constants
    safe_dict = {
        'abs': abs,
        'round': round,
        'min': min,
        'max': max,
        'sum': sum,
        'pow': pow,
        'sqrt': math.sqrt,
        'sin': math.sin,
        'cos': math.cos,
        'tan': math.tan,
        'log': math.log,
        'log10': math.log10,
        'exp': math.exp,
        'ceil': math.ceil,
        'floor': math.floor,
        'pi': math.pi,
        'e': math.e,
        '__builtins__': {},
    }

    try:
        # Parse the code string into an AST
        tree = ast.parse(code_string, mode='eval')

        # Validate that only safe operations are used
        for node in ast.walk(tree):
            # Allow only safe node types
            if isinstance(node, ast.Call):
                if isinstance(node.func, ast.Name):
                    if node.func.id not in safe_dict:
                        return f"Error: Function '{node.func.id}' is not allowed"
                elif isinstance(node.func, ast.Attribute):
                    return "Error: Attribute access is not allowed"
            elif isinstance(node, ast.Name):
                if node.id not in safe_dict and not node.id.replace('_', '').isalnum():
                    pass
            elif isinstance(node, (ast.Import, ast.ImportFrom)):
                return "Error: Import statements are not allowed"
            elif isinstance(node, ast.Subscript):
                return "Error: Subscript access is not allowed"

        # Compile and evaluate the code
        compiled = compile(tree, '<string>', 'eval')
        result = eval(compiled, safe_dict)

        return str(result)

    except SyntaxError as e:
        return f"Syntax Error: {str(e)}"
    except ValueError as e:
        return f"Value Error: {str(e)}"
    except ZeroDivisionError:
        return "Error: Division by zero"
    except TypeError as e:
        return f"Type Error: {str(e)}"
    except Exception as e:
        return f"Error: {str(e)}"

def process_user_expression(expr: str) -> str:
    import re
    import math

    # Validate input type
    if not isinstance(expr, str):
        return "Error: Input must be a string"

    # Strip whitespace
    expr = expr.strip()

    # Check for empty expression
    if not expr:
        return "Error: Expression cannot be empty"

    # Whitelist of allowed characters: digits, operators, parentheses, decimal point, spaces
    # Allow: 0-9, +, -, *, /, %, (, ), ., spaces
    if not re.match(r'^[0-9+\-*/%().\s]+$', expr):
        return "Error: Expression contains invalid characters"

    # Prevent multiple consecutive operators (except minus for negative numbers)
    if re.search(r'[+*/%]\s*[+*/%]', expr):
        return "Error: Invalid operator sequence"

    # Prevent leading operators except minus (for negative numbers)
    if re.match(r'^[+*/%]', expr):
        return "Error: Expression cannot start with this operator"

    # Prevent trailing operators
    if re.search(r'[+\-*/%]\s*$', expr):
        return "Error: Expression cannot end with an operator"

    # Check for balanced parentheses
    if expr.count('(') != expr.count(')'):
        return "Error: Unbalanced parentheses"

    # Prevent nested parentheses depth > 10 (DoS protection)
    max_depth = 0
    current_depth = 0
    for char in expr:
        if char == '(':
            current_depth += 1
            max_depth = max(max_depth, current_depth)
        elif char == ')':
            current_depth -= 1

    if max_depth > 10:
        return "Error: Parentheses nesting too deep"

    # Prevent division by zero by checking for "/0"
    if re.search(r'/\s*0(?:[^0-9.]|$)', expr):
        return "Error: Division by zero"

    # Limit expression length to prevent DoS
    if len(expr) > 1000:
        return "Error: Expression too long"

    try:
        # Use ast.literal_eval for safe evaluation of numeric expressions
        # Since we need to evaluate mathematical expressions, we'll use a restricted approach
        # with compile and eval in a restricted namespace

        # Create a safe namespace with only math functions
        safe_dict = {
            '__builtins__': {},
            'abs': abs,
            'round': round,
            'min': min,
            'max': max,
            'pow': pow,
            'sum': sum,
        }

        # Compile the expression to check for syntax errors
        code = compile(expr, '<string>', 'eval')

        # Evaluate with restricted namespace
        result = eval(code, safe_dict)

        # Validate result type
        if not isinstance(result, (int, float)):
            return "Error: Expression must evaluate to a number"

        # Check for infinity or NaN
        if math.isnan(result) or math.isinf(result):
            return "Error: Result is not a valid number"

        # Return result as string
        if isinstance(result, float) and result.is_integer():
            return str(int(result))
        return str(result)

    except ZeroDivisionError:
        return "Error: Division by zero"
    except SyntaxError:
        return "Error: Invalid expression syntax"
    except NameError:
        return "Error: Undefined variable or function"
    except TypeError:
        return "Error: Invalid operation"
    except Exception as e:
        return f"Error: {type(e).__name__}"

def exec_calculation(calc_string: str) -> str:
    try:
        # Validate input: only allow digits, operators, parentheses, and whitespace
        allowed_chars = set('0123456789+-*/.() \t\n')
        if not all(c in allowed_chars for c in calc_string):
            return "Error: Invalid characters in expression"

        # Prevent empty input
        if not calc_string.strip():
            return "Error: Empty expression"

        # Use ast.literal_eval for safe evaluation of numeric expressions
        # For arithmetic operations, we use a restricted evaluation approach
        import ast
        import operator

        # Parse the expression into an AST
        try:
            tree = ast.parse(calc_string, mode='eval')
        except SyntaxError:
            return "Error: Invalid syntax"

        # Define allowed operations
        ops = {
            ast.Add: operator.add,
            ast.Sub: operator.sub,
            ast.Mult: operator.mul,
            ast.Div: operator.truediv,
            ast.FloorDiv: operator.floordiv,
            ast.Mod: operator.mod,
            ast.Pow: operator.pow,
            ast.UAdd: operator.pos,
            ast.USub: operator.neg,
        }

        def safe_eval(node):
            if isinstance(node, ast.Expression):
                return safe_eval(node.body)
            elif isinstance(node, ast.Constant):
                # Handle numeric constants
                if isinstance(node.value, (int, float)):
                    return node.value
                else:
                    raise ValueError("Only numeric constants allowed")
            elif isinstance(node, ast.Num):  # For Python < 3.8 compatibility
                return node.n
            elif isinstance(node, ast.BinOp):
                left = safe_eval(node.left)
                right = safe_eval(node.right)
                op = ops.get(type(node.op))
                if op is None:
                    raise ValueError("Operation not allowed")
                return op(left, right)
            elif isinstance(node, ast.UnaryOp):
                operand = safe_eval(node.operand)
                op = ops.get(type(node.op))
                if op is None:
                    raise ValueError("Operation not allowed")
                return op(operand)
            else:
                raise ValueError("Expression type not allowed")

        result = safe_eval(tree)

        # Handle division by zero
        if isinstance(result, float) and result == float('inf'):
            return "Error: Division by zero"

        return str(result)

    except ZeroDivisionError:
        return "Error: Division by zero"
    except ValueError as e:
        return f"Error: {str(e)}"
    except Exception as e:
        return f"Error: Invalid expression"
